<script setup lang="ts">
import { doc, getDoc, serverTimestamp, setDoc } from 'firebase/firestore'
import { reportFirebaseError } from '~/utils/firebaseErrors'
const { db }=useFirebaseServices();const { hasPermission }=useAuth();const { showToast,withLoading }=useUi();const loading=ref(false),saving=ref(false);const form=reactive<any>({company_name:'',tax_code:'',phone:'',email:'',address:'',default_vat_rate:0,invoice_note:''})
async function load(){loading.value=true;try{const snap=await getDoc(doc(db,'settings','general'));if(snap.exists())Object.assign(form,snap.data())}catch(error){showToast(reportFirebaseError(error,'Không tải được cài đặt.'),'error')}finally{loading.value=false}}
async function save(){if(!hasPermission('settings.manage'))return showToast('Bạn không có quyền sửa cài đặt.','error');saving.value=true;await withLoading(async()=>{await setDoc(doc(db,'settings','general'),{...form,updated_at:serverTimestamp()},{merge:true});showToast('Đã lưu cài đặt.','success')}).catch(error=>showToast(reportFirebaseError(error,'Không lưu được cài đặt.'),'error')).finally(()=>saving.value=false)}onMounted(load)
</script>
<template><AppShell><PageHeader title="Cài đặt chung" subtitle="Thông tin doanh nghiệp và mặc định chứng từ"/><div class="card"><LoadingState v-if="loading"/><template v-else><div class="form-grid"><div class="form-group"><label>Tên doanh nghiệp</label><input v-model="form.company_name" class="input"/></div><div class="form-group"><label>Mã số thuế</label><input v-model="form.tax_code" class="input"/></div><div class="form-group"><label>Số điện thoại</label><input v-model="form.phone" class="input"/></div><div class="form-group"><label>Email</label><input v-model="form.email" class="input"/></div><div class="form-group"><label>VAT mặc định (%)</label><input v-model.number="form.default_vat_rate" class="input" type="number" min="0"/></div></div><div class="form-group"><label>Địa chỉ</label><textarea v-model="form.address" class="textarea" rows="2"/></div><div class="form-group"><label>Ghi chú hóa đơn mặc định</label><textarea v-model="form.invoice_note" class="textarea" rows="3"/></div><button v-if="hasPermission('settings.manage')" class="btn primary" :disabled="saving" @click="save">Lưu cài đặt</button></template></div></AppShell></template>
